import{indicarProdutosNoCarrinhoEFavoritos}from"./indicador-notificacao.js";function ouvinteBotaoFavoritar(){new botaoFavoritar}class botaoFavoritar{constructor(){this.botoesFavoritos=document.querySelectorAll(".botao-favoritos i"),this.favoritos=JSON.parse(localStorage.getItem("meusFavoritos"))||[]}ouvinteBotaoFavoritar(){this.botoesFavoritos.forEach(e=>{e.addEventListener("click",()=>{let t=e.closest(".card").dataset.id;document.querySelector(".confirmacao-adicao-carrinho");if(this.favoritos.includes(t)){this.favoritos=this.favoritos.filter(o=>o!==t),e.style.color="inherit";let o=document.querySelector(".confirmacao-adicao-carrinho");o.querySelector(".container h5").innerHTML='<i class="fas fa-times-circle me-2" style="color: #dc3545;"></i>Produto removido dos favoritos',o.style.display="flex",setTimeout(()=>{o.querySelector(".container").style.transform="translateY(0)"},200),setTimeout(()=>{o.querySelector(".container").style.transform="translateY(130%)",setTimeout(()=>{o.style.display="none"},600)},1e3)}else{this.favoritos.push(t),e.style.color="gold";let o=document.querySelector(".confirmacao-adicao-carrinho");o.querySelector(".container h5").innerHTML='<i class="fas fa-check-circle me-2" style="color: #28a745;"></i>Produto adicionado aos favoritos',o.style.display="flex",setTimeout(()=>{o.querySelector(".container").style.transform="translateY(0)"},200),setTimeout(()=>{o.querySelector(".container").style.transform="translateY(130%)",setTimeout(()=>{o.style.display="none"},600)},1e3)}localStorage.setItem("meusFavoritos",JSON.stringify(this.favoritos)),indicarProdutosNoCarrinhoEFavoritos()})})}}export{ouvinteBotaoFavoritar};